package kotlin

import (
	"os"
	"path/filepath"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
)

func init() {
	emitter.RegisterFrontend("kotlin", New())
}

// KotlinEmitter generates the frontend Kotlin SDK (generated/client/ApiClient.kt).
type KotlinEmitter struct{}

func (*KotlinEmitter) IsFrontend() {}

// New returns a KotlinEmitter.
func New() *KotlinEmitter { return &KotlinEmitter{} }

// Summary returns a human-friendly breakdown of generated files.
func (e *KotlinEmitter) Summary(modules []string) []emitter.SummaryLine {
	return []emitter.SummaryLine{
		{Dir: "client/", Files: "ApiClient.kt"},
	}
}

// Emit writes generated/client/ApiClient.kt into outDir.
func (e *KotlinEmitter) Emit(a ast.AST, outDir string, opts emitter.EmitOptions) error {
	if opts.DryRun {
		return nil
	}
	dir := filepath.Join(outDir, "client")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	// Collect all used types across all modules (deduplicated).
	allTypes := make(map[string]bool)
	for _, mod := range a.Modules {
		for _, t := range emitter.CollectUsedTypes(a, mod) {
			allTypes[t] = true
		}
	}

	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD — DO NOT EDIT\n")
	sb.WriteString("package veld.generated.client\n\n")
	sb.WriteString("import java.net.URI\n")
	sb.WriteString("import java.net.http.HttpClient\n")
	sb.WriteString("import java.net.http.HttpRequest\n")
	sb.WriteString("import java.net.http.HttpResponse\n")
	sb.WriteString("import kotlinx.serialization.*\n")
	sb.WriteString("import kotlinx.serialization.json.*\n\n")

	// VeldApiError
	sb.WriteString("class VeldApiError(val status: Int, val body: String) : Exception(\"Veld API error $status: $body\")\n\n")

	// Json instance
	sb.WriteString("private val json = Json { ignoreUnknownKeys = true }\n\n")

	emitEnums(&sb, a, allTypes)
	emitDataClasses(&sb, a, allTypes)
	emitApiObject(&sb, a, opts)

	return os.WriteFile(filepath.Join(dir, "ApiClient.kt"), []byte(sb.String()), 0644)
}
